      value: #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1535179"(userName: local!inmate[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/1ae3465f-b22e-4ab3-8656-a047e5f9c3e7"])
    },
    {
      label: #"urn:appian:translation-string:v1:fc0c1b61-cf15-4170-a14f-fdd6ef67c893",
