  },

  #"SYSTEM_SYSRULES_formLayout_v1"(
    label: "Bitte nehmen Sie das Antragsergebnis zur Kenntnis",
    contents: {
      {
        #"SYSTEM_SYSRULES_columnsLayout"(
          columns: {   
            #"SYSTEM_SYSRULES_columnLayout"(
              width: "1X"
            ),
            #"SYSTEM_SYSRULES_columnLayout"(
              contents: {
                #"SYSTEM_SYSRULES_richTextDisplayField"(
                  labelPosition: "COLLAPSED",
                  value: {
                    "Hiermit bestätige ich dass ich das Ergebnis meiner Antragsstellung gelesen und zur Kenntnis genommen habe."
                  },
                  preventWrapping: false,
                  align: "CENTER",
                  marginAbove: "MORE",
                  marginBelow: "MORE"
                ),

                #"SYSTEM_SYSRULES_gridField_v3"(
                  labelPosition: "COLLAPSED",
                  data: local!tableRows,
                  columns: {
                    #"SYSTEM_SYSRULES_gridColumn"(
                      label: "",
                      value: #"SYSTEM_SYSRULES_richTextDisplayField"(
                        value: {
                          #"SYSTEM_SYSRULES_richTextItem_v1"(
                            text: index(fv!row, "label", null),
                            style: "STRONG"
                          )
                        }
                      )
                    ),
                    #"SYSTEM_SYSRULES_gridColumn"(
                      label: "",
                      value: index(fv!row, "value", null)
                    )
                  },
                  pagingSaveInto: {}
                ),

                #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1605697"(
                  text: {      
                    #"urn:appian:translation-string:v1:d185410b-77e9-4d79-847f-a3a077b4cb2d"
                  },
                  label: #"urn:appian:translation-string:v1:63c774cf-5f27-490b-90ae-53f22a550fde"
                )
              },
              width: "10X"
            ),
            #"SYSTEM_SYSRULES_columnLayout"(
              width: "1X"
            )        
          }
        )
      }
    },
    buttons: #"SYSTEM_SYSRULES_ButtonLayout"(
      primaryButtons: {
        #"SYSTEM_SYSRULES_buttonWidget_v1"(
          label: "Bestätigung",
          saveInto: {
            a!save(
              target: ri!request[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/6777c0fa-c69a-4dd5-9ee8-edd15ee79b80"],
              value: true
            ),
            a!save(
              target: ri!request[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/746e407a-2a3a-4a00-b4fc-59b2103b6131"],
              value: loggedInUser()
            ),
            a!save(
              target: ri!request[#"urn:appian:record-field:v1:869b0f23-8e42-4780-8dfc-89deb24c798d/f3ba344c-c6d8-48a9-b57e-2ac2380a8f74"],
              value: now()
            )
          },
          submit: true,
          style: "SOLID"
        )
      }
    )
